import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.math3.optimization.direct.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.math3.optimization.direct.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.math3.exception.NumberIsTooLargeException;
import org.apache.commons.math3.optimization.direct.CMAESOptimizer;
import org.apache.commons.math3.optimization.direct.DirectSearchOptimizer;
import org.apache.commons.math3.optimization.GoalType;
import org.apache.commons.math3.optimization.InitialGuess;
import org.apache.commons.math3.optimization.MaxEval;
import org.apache.commons.math3.optimization.PointValuePair;
import org.apache.commons.math3.optimization.MultivariateFunction;
import org.apache.commons.math3.analysis.MultivariateFunction as MathMultivariateFunction;

import static org.junit.Assert.*;

public class StepDefs {

    private CMAESOptimizer optimizer;
    private double[] startPoint;
    private double[] lowerBound;
    private double[] upperBound;
    private Exception thrownException;

    @Given("a CMAESOptimizer")
    public void a_cmaes_optimizer() {
        optimizer = new CMAESOptimizer(30000, 1e-13, true, 0, 0, null, false);
    }

    @Given("a start point defined as {string}")
    public void a_start_point_defined_as(String startPointStr) {
        // Parse the array string like "[0.0]" to double array
        startPointStr = startPointStr.replaceAll("[\\[\\]]", "");
        String[] parts = startPointStr.split(",");
        startPoint = new double[parts.length];
        for (int i = 0; i < parts.length; i++) {
            startPoint[i] = Double.parseDouble(parts[i].trim());
        }
    }

    @Given("a lower bound defined as {string}")
    public void a_lower_bound_defined_as(String lowerBoundStr) {
        // Parse the array string like "[-1.0e308]" to double array
        lowerBoundStr = lowerBoundStr.replaceAll("[\\[\\]]", "");
        String[] parts = lowerBoundStr.split(",");
        lowerBound = new double[parts.length];
        for (int i = 0; i < parts.length; i++) {
            lowerBound[i] = Double.parseDouble(parts[i].trim());
        }
    }

    @Given("an upper bound defined as {string}")
    public void an_upper_bound_defined_as(String upperBoundStr) {
        // Parse the array string like "[1.0e308]" to double array
        upperBoundStr = upperBoundStr.replaceAll("[\\[\\]]", "");
        String[] parts = upperBoundStr.split(",");
        upperBound = new double[parts.length];
        for (int i = 0; i < parts.length; i++) {
            upperBound[i] = Double.parseDouble(parts[i].trim());
        }
    }

    @When("I attempt to optimize a function")
    public void i_attempt_to_optimize_a_function() {
        try {
            // Define a simple multivariate function to optimize
            MultivariateFunction function = new MultivariateFunction() {
                @Override
                public double value(double[] point) {
                    // A simple function for testing
                    double sum = 0;
                    for (int i = 0; i < point.length; i++) {
                        sum += point[i] * point[i];
                    }
                    return sum;
                }
            };

            // Perform optimization
            PointValuePair result = optimizer.optimize(
                100, // max evaluations
                function,
                GoalType.MINIMIZE,
                startPoint,
                lowerBound,
                upperBound
            );
        } catch (Exception e) {
            thrownException = e;
        }
    }

    @Then("a NumberIsTooLargeException should be thrown")
    public void a_number_is_too_large_exception_should_be_thrown() {
        assertNotNull("Exception should have been thrown", thrownException);
        assertTrue("Exception should be NumberIsTooLargeException", 
                   thrownException instanceof NumberIsTooLargeException);
    }
